(lib.text1 = function(mode,startPosition,loop) {
	this.initialize(mode,startPosition,loop,{});

	// timeline functions:
	this.frame_0 = function() {
		var that = this;
		
		that.isListener;
		
		var allTrue = true;
		var txtArray = [];
		
		
		// get the movieclip  starts with link on stage 
		
		
		function getTxt() {
		
		
			var parent = that.correctbtn.parent;
			var keys = Object.keys(parent);
			var len = keys.length;
		
			while (--len) {
		
		
				if (keys[len].slice(1, 4) === ("txt")) {
		
					console.log("txt  : " + keys[len]);
		
					document.getElementById(keys[len]).insName = keys[len];
					document.getElementById(keys[len]).maxLength = 10;
					
					txtArray.push(document.getElementById(keys[len]));
				}
			}
		
		
		}
		
		
		function setlisteners() {
		
			if (!that.isListener) {
		
		
				that.correctbtn.addEventListener("click", correcrtxt);
				that.rebtn.addEventListener("click", reply);
		
		
		
				that.isListener = true;
			}
		
		
		}
		
		
		
		setTimeout(function () {
		
		
			getTxt();
		
			setlisteners();
		
			initTextStyle();
		
		
		}, 0);
		
		function initTextStyle() {
		
		
			for (var t = 0; t < txtArray.length; t++) {
		
				txtArray[t].style.color = '#000000';
				txtArray[t].style.fontSize = "24px";
				txtArray[t].style.fontFamily = "'Comic Sans MS', cursive, sans-serif";
		
		
			}
		
		
		}
		
		
		function correcrtxt() {
		
			that.correctbtn.removeEventListener("click", correcrtxt);
		
			for (var u = 0; u < txtArray.length; u++) {
		
		
		
				if (txtArray[u].value !== txtArray[u].insName.slice(4)) {
		
					txtArray[u].style.color = '#ff0000';
					allTrue = false;
		
				}
			}
		
			if (allTrue) {
		
				alert("  ahsannnnnnt  !!");
		
			}
		
		}
		function reply() {
		
			that.correctbtn.addEventListener("click", correcrtxt);
		
			allTrue = true;
		
			initTextStyle();
		
			for (var u = 0; u < txtArray.length; u++) {
		
				txtArray[u].value = "";
		
			}
		}
	}

	// actions tween:
	this.timeline.addTween(cjs.Tween.get(this).call(this.frame_0).wait(1));

	// Layer_2
	this.Rtxt2 = new lib.an_TextInput({'id': 'Rtxt2', 'value':'', 'disabled':false, 'visible':true, 'class':'ui-textinput'});

	this.Rtxt2.setTransform(351,54.05,1,1,0,0,0,50,11);

	this.Ytxt1 = new lib.an_TextInput({'id': 'Ytxt1', 'value':'', 'disabled':false, 'visible':true, 'class':'ui-textinput'});

	this.Ytxt1.setTransform(137.05,52.05,1,1,0,0,0,50,11);

	this.rebtn = new lib.replay();
	this.rebtn.name = "rebtn";
	this.rebtn.parent = this;
	this.rebtn.setTransform(455.1,157.35,1,1,0,0,0,24.3,24.9);

	this.correctbtn = new lib.correct();
	this.correctbtn.name = "correctbtn";
	this.correctbtn.parent = this;
	this.correctbtn.setTransform(354.6,160.8,1,1,0,0,0,25.4,26.4);

	this.timeline.addTween(cjs.Tween.get({}).to({state:[{t:this.correctbtn},{t:this.rebtn},{t:this.Ytxt1},{t:this.Rtxt2}]}).wait(1));

}).prototype = getMCSymbolPrototype(lib.text1, new cjs.Rectangle(86.6,40.6,393.20000000000005,147.3), null);


