		var cmd, c;
		
		var downOnAcceptedMc, isListener, lineToErase, currentUpMc, mmc, ismove;
		
		
		var allTrue = true;
		
		var linkArray = [];
		var TwomcArray = [];
		var mc1Array = [];
		var mc2Array = [];
		
