(lib.mini_slder = function(mode,startPosition,loop) {
	this.initialize(mode,startPosition,loop,{});

	// timeline functions:
	this.frame_0 = function() {
		var that = this;
		
		var stopReceivingOnTickSound;
		
		
		this.trk.addEventListener("pressup", onpressup);
		this.trk.addEventListener("pressmove", onpressmove.bind(this));
		this.trk.addEventListener("mousedown", onmousedown.bind(this));
		
		var trkWidth = that.trk.getBounds().width;
		var sldWidth = that.sld.getBounds().width;
		that.rate = 0;
		
		
		var totalFrm = that.parent.parent.mov.totalFrames;
		
		function onmousedown(e) {
		
			var pt = this.globalToLocal(e.stageX, e.stageY);
			var posX = pt.x;
			var posY = pt.y;
		
			stopReceivingOnTickSound = true;
		
		}
		
		
		function onpressmove(e) {
		
		
			var pt = this.globalToLocal(e.stageX, e.stageY);
		
		
		
			if (pt.x >= 0 && pt.x <= sldWidth) {
		
				var newX = pt.x;
		
		
				that.trk.x = newX;
		
		
				//	alert("that.parent.parent "+that.parent.parent.parent);
		
			}
		}
		
		
		//Mouse UP and SNAP====================
		function onpressup(evt) {
		
		
			trkRate(that.trk.x);
		
			that.parent.parent.mov.gotoAndPlay(totalFrm * that.rate);
		
			that.parent.resetSoundPosition(that.rate);
		
			//we change this variable after setting the new sound position 
			//to start updating the trk position on tick function from sound
		
			stopReceivingOnTickSound = false;
		}
		
		
		function trkRate(currentPosition) {
		
			var cur = currentPosition < 0 ? 0 : currentPosition > sldWidth ? sldWidth : currentPosition;
			that.rate = cur / sldWidth;
			return that.rate;
		}
		
		that.resetTrk = function (rate) {
		
			if (!stopReceivingOnTickSound) {
		
				that.trk.x = sldWidth * rate;
				that.rate = rate;
		
			}
		}
		
		
		that.addEventListener("removed", removeListeners);
		
		function removeListeners(e) {
		
		
			that.trk.removeEventListener("pressup", onpressup);
			that.trk.removeEventListener("pressmove", onpressmove);
			that.trk.removeEventListener("mousedown", onmousedown);
		
		
			that.removeEventListener("removed", removeListeners);
		
		
		
		}
	}

	// actions tween:
	this.timeline.addTween(cjs.Tween.get(this).call(this.frame_0).wait(1));

	// Layer_2
	this.trk = new lib.trkcopy();
	this.trk.name = "trk";
	this.trk.parent = this;
	this.trk.setTransform(0,0,0.6458,1);

	this.sld = new lib.sldcopy();
	this.sld.name = "sld";
	this.sld.parent = this;
	this.sld.setTransform(103,-0.9,1,1,0,0,0,103,4.1);

	this.timeline.addTween(cjs.Tween.get({}).to({state:[{t:this.sld},{t:this.trk}]}).wait(1));

}).prototype = getMCSymbolPrototype(lib.mini_slder, new cjs.Rectangle(-11.6,-18,217.9,35.4), null);


